$jq(document).ready(function() {

    var url = $jq('a.dell-corp').attr('href');
    var url2 = $jq('a.privacy').attr('href');

    	if (window.location.href.indexOf("pt-br") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/br/pt/brcorp1/site-terms-of-use-copyright');
            var url2 = url2.replace('ca/en/cacorp1', 'br/pt/brcorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/br/pt/brcorp1/site-terms-of-use");
    	}

    	else if (window.location.href.indexOf("es-mx") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/mx/es/mxcorp1/terms-conditions/art-site-terms-of-use-copyright?c=mx&l=es&s=corp');
            var url2 = url2.replace('ca/en/cacorp1', 'mx/es/mxcorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/mx/es/mxcorp1/site-terms-of-use");
    	}

    	else if (window.location.href.indexOf("de-de") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/de/de/decorp1/site-terms-of-use-copyright');
            var url2 = url2.replace('ca/en/cacorp1', 'de/de/decorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/de/de/decorp1/site-terms-of-use");
    	}

    	else if (window.location.href.indexOf("fr-fr") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/fr/fr/frcorp1/site-terms-of-use-copyright');
            var url2 = url2.replace('ca/en/cacorp1', 'fr/fr/frcorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/fr/fr/frcorp1/site-terms-of-use");
    	}

    	else if (window.location.href.indexOf("ja-jp") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/jp/ja/jpcorp1/site-terms-of-use-copyright');
            var url2 = url2.replace('ca/en/cacorp1', 'jp/ja/jpcorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/jp/ja/jpcorp1/site-terms-of-use");
    	}

    	else if (window.location.href.indexOf("ko-kr") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/kr/ko/krcorp1/site-terms-of-use-copyright');
            var url2 = url2.replace('ca/en/cacorp1', 'kr/ko/krcorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/kr/ko/krcorp1/site-terms-of-use");
    	}

    	else if (window.location.href.indexOf("zh-cn") > -1) {
    		var url = url.replace('https://www.dell.com/learn/ca/en/cacorp1/terms-conditions/site-terms-of-use-copyright-ca', 'https://www.dell.com/learn/cn/zh/cncorp1/site-terms-of-use-copyright');
            var url2 = url2.replace('ca/en/cacorp1', 'cn/zh/cncorp1');
    		$jq("a.terms-of-use").attr("href", "https://www.dell.com/learn/cn/zh/cncorp1/site-terms-of-use");
    	}

    	$jq('a.dell-corp').attr('href', url);
        $jq('a.privacy').attr('href', url2);

    $jq(".aemghf-language-name").attr("id", "aemghf-education-location");
	var locationHeader = "", localeheader = "";
	if (readCookie('GSSSiteIcon') != null) {
		localeheader = readCookie('GSSSiteIcon');
		$jq(".aemghf-language-name").text(localeheader);
	}
	if(readCookie('GSSSiteUrl') != null) {
        locationHeader = readCookie('GSSSiteUrl');
        var firstPart = locationHeader.split('-')[0];
        var secondPart = locationHeader.split('-')[1];
        // 12-22-22 Comment by Vinay - Added if condition to check if the element is present on the page to fetch the value as if was causing issue on EULA page
        if (window.location.href.indexOf("eula.html") == -1) {
                	Dell.Metrics.sc.language = firstPart;
                	Dell.Metrics.sc.country = secondPart;
                }
	}
});
